// Auth Check v5 — tenant_auth DataTable with SHA-256 hash verification
// All keys must be registered in tenant_auth via Golden Path onboarding
// Legacy $vars fallback removed (2026-03-15)
const crypto = require('crypto');

// ===== PERMISSION CHECKER (F1: 3-tier permission model) =====
// Permission levels: read < read_write < admin
// read: GET + low risk only
// read_write: all methods except high-risk (DELETE bulk, dangerous ops)
// admin: everything including high-risk
function checkPermission(permissionLevel, method, riskLevel) {
  if (!permissionLevel) return { allowed: false, reason: 'No permission level assigned' };

  if (permissionLevel === 'admin') return { allowed: true };

  if (permissionLevel === 'read_write') {
    if (riskLevel === 'high') {
      return { allowed: false, reason: "Permission 'read_write' insufficient for high-risk operations (requires admin)" };
    }
    return { allowed: true };
  }

  if (permissionLevel === 'read') {
    if (method !== 'GET' && method !== 'HEAD' && method !== 'OPTIONS') {
      return { allowed: false, reason: "Permission 'read' only allows GET/HEAD/OPTIONS methods" };
    }
    if (riskLevel && riskLevel !== 'low') {
      return { allowed: false, reason: "Permission 'read' only allows low-risk endpoints" };
    }
    return { allowed: true };
  }

  return { allowed: false, reason: "Unknown permission level: '" + permissionLevel + "'" };
}
// ===== END PERMISSION CHECKER =====


const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const apiKey = headers['x-api-key'] || '';

if (!apiKey) {
  return [{json: {
    authenticated: false,
    error: {type: 'auth_error', message: 'Missing x-api-key header', details: {}},
    body, headers
  }}];
}

// --- SHA-256 hash verification ---
function verifyApiKey(plainTextKey, storedHash) {
  const parts = storedHash.split(':');
  if (parts.length !== 3 || parts[0] !== 'sha256') return false;
  const salt = parts[1];
  const expectedHash = parts[2];
  const actualHash = crypto.createHash('sha256').update(salt + plainTextKey).digest('hex');
  return actualHash === expectedHash;
}

// --- Fetch tenant_auth rows ---
const n8nHost = $vars.N8N_HOST;
const internalKey = $vars.N8N_INTERNAL_API_KEY;
const tenantAuthTableId = $vars.TENANT_AUTH_TABLE_ID;

let tenantMatch = null;
let authSource = 'none';

try {
  let allRows = [];
  let cursor = '';
  let hasMore = true;
  while (hasMore) {
    const url = `${n8nHost}/api/v1/data-tables/${tenantAuthTableId}/rows?limit=250${cursor ? '&cursor=' + cursor : ''}`;
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: { 'X-N8N-API-KEY': internalKey }
    });
    allRows = allRows.concat(resp.data || []);
    cursor = resp.nextCursor || '';
    hasMore = !!resp.nextCursor && resp.data && resp.data.length > 0;
  }

  // Iterate rows and verify API key hash
  for (const row of allRows) {
    if (!row.api_key_hash) continue;
    if (verifyApiKey(apiKey, row.api_key_hash)) {
      tenantMatch = row;
      authSource = 'tenant_auth';
      break;
    }
  }
} catch (e) {
  // If tenant_auth lookup fails entirely, log and continue to fallback
  // Fail-closed: if no fallback matches either, deny
}

// --- Validate tenant match ---
if (tenantMatch) {
  // Check active
  if (tenantMatch.active !== true && tenantMatch.active !== 'true') {
    return [{json: {
      authenticated: false,
      error: {type: 'auth_error', message: 'API key deactivated', details: {client_id: tenantMatch.client_id}},
      body, headers
    }}];
  }

  // Check expiry
  if (tenantMatch.expires_at && tenantMatch.expires_at !== 'never') {
    const expiresAt = new Date(tenantMatch.expires_at);
    if (expiresAt < new Date()) {
      return [{json: {
        authenticated: false,
        error: {type: 'auth_error', message: 'API key expired', details: {client_id: tenantMatch.client_id, expired_at: tenantMatch.expires_at}},
        body, headers
      }}];
    }
  }

  // Parse domain permissions
  let permissions = {};
  try {
    permissions = JSON.parse(tenantMatch.domain_permissions || '{}');
  } catch(e) {
    permissions = {};
  }

  // Check domain permission
  const domain = body.domain || '';
  const action = body.action || '';
  let permissionLevel = permissions[domain] || permissions['*'] || null;

  if (!permissionLevel && domain) {
    return [{json: {
      authenticated: false,
      error: {type: 'permission_error', message: 'Domain not authorized: ' + domain, details: {client_id: tenantMatch.client_id, allowed_domains: Object.keys(permissions)}},
      body, headers
    }}];
  }

  // F1: 3-tier permission enforcement (read / read_write / admin)
  const WRITE_PATTERNS = /(?:^|[_.\s])(create|update|send|reply|draft|move|copy|mutate|upsert|composite|write|append|clear|batch_update|upload|render|generate|image_to_image|upscale|reactions_add)(?:$|[_.\s])/i;
  const DELETE_PATTERNS = /(?:^|[_.\s])(delete|remove|purge|destroy|bulk_delete|trash)(?:$|[_.\s])/i;
  const HIGH_RISK_PATTERNS = /(?:^|[_.\s])(delete|bulk_delete|purge|destroy|permissions|admin)(?:$|[_.\s])/i;

  let inferredMethod = 'GET';
  let inferredRisk = 'low';
  if (DELETE_PATTERNS.test(action)) {
    inferredMethod = 'DELETE';
    inferredRisk = 'high';
  } else if (HIGH_RISK_PATTERNS.test(action)) {
    inferredMethod = 'POST';
    inferredRisk = 'high';
  } else if (WRITE_PATTERNS.test(action)) {
    inferredMethod = 'POST';
    inferredRisk = 'medium';
  }

  const permCheck = checkPermission(permissionLevel, inferredMethod, inferredRisk);
  if (!permCheck.allowed) {
    return [{json: {
      authenticated: false,
      error: {type: 'permission_error', message: permCheck.reason + ' (domain: ' + domain + ', action: ' + action + ')', details: {client_id: tenantMatch.client_id, permission: permissionLevel, method: inferredMethod, risk: inferredRisk}},
      body, headers
    }}];
  }

  // === ADMIN KEY ALERT (A4) ===
  if (tenantMatch.client_id === 'ascend_admin') {
    // Log warning — admin key used
    // This will be visible in execution data for monitoring
    console.log('⚠️ ADMIN KEY USED — client_id: ascend_admin, domain: ' + domain + ', action: ' + action + ', timestamp: ' + new Date().toISOString());
  }

  return [{json: {
    authenticated: true,
    authSource: 'tenant_auth',
    clientId: tenantMatch.client_id,
    keyClient: tenantMatch.client_id === 'legacy_master' ? '*' : tenantMatch.client_id,
    keyScope: tenantMatch.client_id === 'ascend_admin' ? 'master' : 'standard',
    keyName: 'tenant_auth:' + tenantMatch.client_id,
    permissionLevel: permissionLevel,
    rateLimitPerMinute: tenantMatch.rate_limit_per_minute || 60,
    credentialSet: tenantMatch.credential_set || 'default',
    body, headers
  }}];
}

// --- No tenant_auth match: deny access ---
// Legacy fallback removed — all keys must be in tenant_auth DataTable
return [{json: {
  authenticated: false,
  error: {type: 'auth_error', message: 'Invalid API key', details: {hint: 'Key not found in tenant_auth. All keys must be registered via Golden Path onboarding.'}},
  body, headers
}}];

// Input Validator v2
const {body, keyClient, keyScope} = $input.first().json;
const {domain, action, client, params, mode, meta} = body || {};

const errors = [];
if (!domain) errors.push('domain is required');
if (!action) errors.push('action is required');

const resolvedClient = client || (keyClient === '*' ? 'all' : keyClient);
const resolvedMode = mode || 'sync';
const resolvedMeta = Object.assign({}, meta || {});
if (!resolvedMeta.request_id) {
  resolvedMeta.request_id = 'req_' + Date.now() + '_' + Math.random().toString(36).substr(2,9);
}
resolvedMeta.source = resolvedMeta.source || 'unknown';
resolvedMeta.dry_run = resolvedMeta.dry_run || false;

if (errors.length > 0) {
  return [{json: {
    valid: false,
    error: {type: 'validation_error', message: errors.join('; '), details: {missing: errors}},
    domain: domain || null, action: action || null, client: resolvedClient, mode: resolvedMode, meta: resolvedMeta
  }}];
}

return [{json: {
  valid: true,
  domain, action,
  client: resolvedClient,
  params: params || {},
  mode: resolvedMode,
  meta: resolvedMeta,
  keyClient, keyScope
}}];

// Registry Lookup — cursor-paginated fetch from api_registry_v2
const infra = $json._infra;
const allRows = [];
let cursor = '';
let hasMore = true;
let pages = 0;

while (hasMore && pages < 20) {
  pages++;
  const url = infra.registry_url + '?limit=250' + (cursor ? '&cursor=' + cursor : '');
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'X-N8N-API-KEY': infra.api_key },
    json: true
  });
  allRows.push(...(resp.data || []));
  cursor = resp.nextCursor || '';
  hasMore = !!resp.nextCursor && (resp.data || []).length > 0;
}

// Output same shape as original HTTP Request node for Resolve Config compatibility
const prev = $input.first().json;
return [{ json: { ...prev, data: allRows } }];

// Action Lookup — cursor-paginated fetch from action_map_v2
// Principle 6: Error handling with try/catch
const infra = $('Prepare Infra URLs').first().json._infra;
const allRows = [];
let cursor = '';
let hasMore = true;
let pages = 0;

try {
  while (hasMore && pages < 20) {
    pages++;
    const url = infra.action_url + '?limit=250' + (cursor ? '&cursor=' + cursor : '');
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { 'X-N8N-API-KEY': infra.api_key },
      json: true
    });
    allRows.push(...(resp.data || []));
    cursor = resp.nextCursor || '';
    hasMore = !!resp.nextCursor && (resp.data || []).length > 0;
  }
} catch (error) {
  // Fail the request if action lookup fails — can't route without actions
  const prev = $input.first().json;
  return [{ json: { ...prev, data: [], _action_lookup_error: error.message } }];
}

const prev = $input.first().json;
return [{ json: { ...prev, data: allRows } }];

// Resolve Config v2 - match registry + action map + tenant config
const input = $('Input Validator').first().json;
const {domain, action, client, params, mode, meta, keyClient, keyScope} = input;

const registryData = $('Registry Lookup').first().json;
const actionData = $('Action Lookup').first().json;
const registryRows = registryData.data || [];
const actionRows = actionData.data || [];

// Find registry: exact client first, then 'all' fallback
const findBest = (rows, apiName, clientMatch) => {
  const matches = rows.filter(r => r.api_name === apiName && r.client === clientMatch && r.enabled);
  if (matches.length <= 1) return matches[0] || null;
  const withValidMeta = [...matches].reverse().find(r => {
    if (!r.metadata || r.metadata === '{}') return false;
    try { const m = typeof r.metadata === 'string' ? JSON.parse(r.metadata) : r.metadata; return m && typeof m === 'object' && Object.keys(m).length > 0; } catch(e) { return false; }
  });
  return withValidMeta || matches[0];
};
let reg = findBest(registryRows, domain, client);
if (!reg) reg = findBest(registryRows, domain, 'all');
if (reg && !reg.handler_workflow_id) { const hFb = findBest(registryRows, domain, 'all'); if (hFb && hFb.handler_workflow_id) reg = hFb; }

if (!reg) {
  return [{json: {
    resolved: false,
    error: {type: 'registry_error', message: 'No registry entry for domain ' + domain + ' client ' + client, details: {domain, client}},
    domain, action, client, mode, meta
  }}];
}

// Prefer newest action_map row with non-empty endpoint
const actionShort = action.startsWith(domain + '.') ? action.slice(domain.length + 1) : action;
const actMatches = actionRows.filter(a => a.api_name === domain && (a.action === action || a.action === actionShort) && a.enabled);
// Prefer handler body_mode over passthrough when both exist for same action
const handlerMatches = actMatches.filter(a => a.body_mode === 'handler');
const withEndpoint = actMatches.filter(a => a.endpoint && a.endpoint.length > 1);
const act = (handlerMatches.length > 0 ? handlerMatches[handlerMatches.length - 1] : withEndpoint.length > 0 ? withEndpoint[withEndpoint.length - 1] : actMatches[actMatches.length - 1]) || null;
if (!act) {
  return [{json: {
    resolved: false,
    error: {type: 'action_error', message: 'No action ' + action + ' for domain ' + domain, details: {domain, action}},
    domain, action, client, mode, meta
  }}];
}

let metadata = {};
try { metadata = typeof reg.metadata === 'string' ? JSON.parse(reg.metadata) : (reg.metadata || {}); } catch(e) {}

// === TENANT CONFIG LOOKUP ===
let tenantConfig = null;
const infra = $('Prepare Infra URLs').first().json._infra || {};
if (infra.tenant_config_url) {
  try {
    const tenantResp = await this.helpers.httpRequest({
      method: 'GET',
      url: infra.tenant_config_url + '?limit=50',
      headers: { 'X-N8N-API-KEY': infra.api_key },
      json: true
    });
    const tenants = (tenantResp.data || []);
    // Use last match (highest ID wins) for given client
    const matches = tenants.filter(t => t.tenant_id === client);
    const match = matches.length > 0 ? matches[matches.length - 1] : null;
    if (match && match.status === 'active') {
      tenantConfig = {
        tenant_id: match.tenant_id,
        display_name: match.display_name,
        status: match.status,
        env: match.env,
        connected_tools: (() => { try { return JSON.parse(match.connected_tools || '{}'); } catch(e) { return {}; } })(),
        credential_map: (() => { try { return JSON.parse(match.credential_map || '{}'); } catch(e) { return {}; } })(),
        feature_flags: (() => { try { return JSON.parse(match.feature_flags || '{}'); } catch(e) { return {}; } })(),
        metadata: (() => { try { return JSON.parse(match.metadata || '{}'); } catch(e) { return {}; } })()
      };
    }
  } catch (e) {
    // Don't fail the request if tenant lookup fails — fallback to existing behavior
  }
}

// Override handler_workflow_id for domains with known handlers but broken registry entries
const HANDLER_OVERRIDES = {
  'bedrock': 'pReqgWyL8hbeLZlr'
};
if (HANDLER_OVERRIDES[domain] && !reg.handler_workflow_id) {
  reg.handler_workflow_id = HANDLER_OVERRIDES[domain];
}

const config = {
  api_name: reg.api_name, base_url: reg.base_url || '',
  auth_type: reg.auth_type, auth_header: reg.auth_header || '',
  auth_prefix: reg.auth_prefix || '', credential_var: reg.credential_var || '',
  credential_id: reg.credential_id || '', credential_type: reg.credential_type || '',
  handler_workflow_id: reg.handler_workflow_id || '',
  metadata, rate_limit_rpm: reg.rate_limit_rpm || 60
};

// Enrich config with tenant data if available
if (tenantConfig) {
  config.tenant = tenantConfig;
  config.tenant_metadata = tenantConfig.metadata;
  config.tenant_credential = tenantConfig.credential_map[domain] || null;
}

return [{json: {
  resolved: true, domain, action, client, params, mode, meta,
  config,
  actionConfig: { method: act.method, endpoint: act.endpoint || '', body_mode: act.body_mode }
}}];

// ===== SSRF PROTECTION (A5) =====
function validatePath(path) {
  if (!path || typeof path !== 'string') return { valid: false, reason: 'Path is required' };
  if (path.includes('..') || path.includes('//')) return { valid: false, reason: 'Path traversal detected' };
  if (path.includes('\\0') || path.includes('%00')) return { valid: false, reason: 'Null byte in path' };
  if (!path.startsWith('/')) path = '/' + path;
  return { valid: true, path };
}
function validateRequestBody(body) {
  if (!body) return { valid: true };
  const s = typeof body === 'string' ? body : JSON.stringify(body);
  if (s.length > 1048576) return { valid: false, reason: 'Request body exceeds 1MB limit' };
  return { valid: true };
}
// ===== END SSRF PROTECTION =====

// Build Dynamic Request for passthrough APIs
// ZERO hardcoded domain names — all injection is config-driven via tenant_metadata
const {domain, action, client, params, mode, meta, config, actionConfig} = $input.first().json;

let url = config.base_url || '';
let endpoint = actionConfig.endpoint || '';

// Replace path params like {model}
endpoint = endpoint.replace(/\{(\w+)\}/g, (m, key) => params[key] || m);
// SSRF: Validate endpoint path before URL construction
const pathCheck = validatePath(endpoint);
if (!pathCheck.valid) {
  return [{json: { error: true, message: 'SSRF protection: ' + pathCheck.reason, domain, action }}];
}
endpoint = pathCheck.path;
url = url.replace(/\/+$/, '') + endpoint;

const method = actionConfig.method || 'POST';
const headers = method === 'GET' ? {} : {'Content-Type': 'application/json'};
const queryParams = {};

// Auth: inject API key as header or query param
if (config.auth_type === 'header' && config.credential_var) {
  const apiKey = $vars[config.credential_var];
  if (apiKey) {
    const prefix = config.auth_prefix ? config.auth_prefix + ' ' : '';
    headers[config.auth_header] = prefix + apiKey;
  }
}

if (config.auth_type === 'query' && config.credential_var) {
  const apiKey = $vars[config.credential_var];
  if (apiKey) queryParams['key'] = apiKey;
}

// Auth: basic auth (e.g., Gong)
if (config.auth_type === 'basic' && config.credential_var) {
  const cred = $vars[config.credential_var] || '';
  if (cred.includes(':')) {
    headers['Authorization'] = 'Basic ' + Buffer.from(cred).toString('base64');
  } else {
    const secret = $vars[config.credential_var.replace('ACCESS_KEY','SECRET_KEY')]
      || $vars[config.credential_var.replace('ACCESS_KEY','CLIENT_SECRET')]
      || $vars[config.credential_var.replace('ACCESS_KEY_KAHUNA','CLIENT_SECRET_KAHUNA')]
      || '';
    headers['Authorization'] = 'Basic ' + Buffer.from(cred + ':' + secret).toString('base64');
  }
}

// Domain-specific headers from registry metadata (e.g., anthropic-version, Notion-Version)
// These are per-API requirements, not per-tenant — stored in api_registry_v2.metadata
if (config.metadata && config.metadata._headers) {
  for (const [hKey, hVal] of Object.entries(config.metadata._headers)) {
    headers[hKey] = hVal;
  }
}

// === TENANT METADATA AUTO-INJECTION (config-driven, zero hardcoded domains) ===
// tenant_metadata is domain-keyed: {"ga4": {"property_id": "123"}, "gong": {"_base_url": "..."}}
// Convention:
//   _base_url     → overrides the request URL base
//   _header_*     → injected as HTTP header (key after prefix)
//   anything else → injected as param default (only if not already set by caller)
if (config.tenant_metadata && config.tenant_metadata[domain]) {
  const domainMeta = config.tenant_metadata[domain];
  for (const [key, value] of Object.entries(domainMeta)) {
    if (key === '_base_url') {
      // Override base URL (e.g., Gong has per-tenant API base)
      url = value + endpoint;
    } else if (key.startsWith('_header_')) {
      // Inject as HTTP header (e.g., _header_login-customer-id → login-customer-id header)
      headers[key.slice(8)] = value;
    } else if (!params[key]) {
      // Inject as param default (only if caller didn't already provide it)
      params[key] = value;
    }
  }
}

// Forward params: GET→query, POST/PATCH/PUT/DELETE→body
let body = {};
let extraQueryParams = {};
if (method === 'GET') {
  extraQueryParams = params;
  body = null;
} else {
  body = params;
}

// SSRF: Validate request body size
const bodyCheck = validateRequestBody(body);
if (!bodyCheck.valid) {
  return [{json: { error: true, message: 'SSRF protection: ' + bodyCheck.reason, domain, action }}];
}

// Build full URL with query params
let fullUrl = url;
const mergedQP = Object.assign({}, queryParams, extraQueryParams);
const qp = Object.entries(mergedQP);
if (qp.length > 0) {
  fullUrl += (url.includes('?') ? '&' : '?') + qp.map(([k,v]) => k + '=' + encodeURIComponent(v)).join('&');
}

// Validate: no unresolved {placeholders} in URL
const unresolvedMatch = fullUrl.match(/\{(\w+)\}/);
if (unresolvedMatch) {
  return [{json: {
    validationError: true,
    ok: false,
    error: {
      type: 'validation',
      message: `Missing required param '${unresolvedMatch[1]}' for ${domain}/${action}. The endpoint requires '${unresolvedMatch[1]}' in params.`
    },
    domain, action, client, mode, meta
  }}];
}

var bodyJson = (method === "GET" || !body) ? "" : JSON.stringify(body);
return [{json: {
  requestUrl: fullUrl, requestMethod: method,
  requestHeaders: headers, requestBody: body, bodyJson: bodyJson,
  domain, action, client, mode, meta, config
}}];

// Format Handler Response + Failure Alerting (ADR-001 Phase 2)
const h = $input.first().json;
const r = $('Resolve Config').first().json;
const {domain, action, client, mode, meta} = r;
const infra = $('Prepare Infra URLs').first().json._infra || {};

const isV2 = h.hasOwnProperty('ok');
const isError = isV2 ? !h.ok : false;

// Track failures: 3 per domain in 5 min -> Slack alert
if (isError && domain && infra.n8n_host) {
  try {
    const COUNTER_TABLE = $vars.RATE_LIMIT_TABLE_ID || 'FsTInkNFnck4KNrp';
    const now = new Date();
    const fiveMinAgo = new Date(now.getTime() - 5 * 60 * 1000).toISOString();

    // Write this failure
    await this.helpers.httpRequest({
      method: 'POST',
      url: infra.n8n_host + '/api/v1/data-tables/' + COUNTER_TABLE + '/rows',
      headers: {'X-N8N-API-KEY': infra.api_key, 'Content-Type': 'application/json'},
      body: JSON.stringify({data: [{
        domain: domain, client: client || 'unknown',
        error_type: (h.error && h.error.type) || 'handler_error',
        error_message: (h.error && h.error.message) || 'unknown',
        timestamp: now.toISOString(),
        source: 'handler'
      }]})
    });

    // Read recent failures for this domain
    const counters = await this.helpers.httpRequest({
      method: 'GET',
      url: infra.n8n_host + '/api/v1/data-tables/' + COUNTER_TABLE + '/rows?limit=250',
      headers: {'X-N8N-API-KEY': infra.api_key},
      json: true
    });
    const recent = (counters.data || []).filter(r => 
      r.domain === domain && r.timestamp && r.timestamp > fiveMinAgo
    );

    // Alert if threshold exceeded (3 failures in 5 min)
    if (recent.length >= 3) {
      // Check if we already alerted (avoid storm)
      const alertKey = 'alert_' + domain;
      const recentAlerts = (counters.data || []).filter(r => 
        r.domain === alertKey && r.timestamp && r.timestamp > fiveMinAgo
      );

      if (recentAlerts.length === 0) {
        // Fire Slack alert
        try {
          const slackUrl = infra.n8n_host + '/webhook/handler-google-suite';
          await this.helpers.httpRequest({
            method: 'POST', url: slackUrl,
            headers: {'x-handler-secret': infra.handler_secret, 'Content-Type': 'application/json'},
            body: JSON.stringify({
              domain: 'slack', action: 'post_message', client: 'ascend',
              params: {
                channel: '#n8n-alerts',
                text: ':rotating_light: *Gateway Failure Alert*\n*Domain:* ' + domain + '\n*Failures:* ' + recent.length + ' in last 5 min\n*Error:* ' + ((h.error && h.error.message) || 'unknown') + '\n*Client:* ' + (client || 'unknown') + '\n*Action:* Investigate via `get_platform_context`'
              }
            })
          });
        } catch(e) {} // Alert is best-effort

        // Mark alert sent
        try {
          await this.helpers.httpRequest({
            method: 'POST',
            url: infra.n8n_host + '/api/v1/data-tables/' + COUNTER_TABLE + '/rows',
            headers: {'X-N8N-API-KEY': infra.api_key, 'Content-Type': 'application/json'},
            body: JSON.stringify({data: [{domain: alertKey, timestamp: now.toISOString(), source: 'alert_sent'}]})
          });
        } catch(e) {}
      }
    }
  } catch(e) {} // Failure tracking is best-effort, never blocks the response
}

if (isV2) {
  return [{json: {ok: h.ok, domain, action, client, mode, meta: Object.assign({}, meta, {execution_id: $execution.id, timestamp: new Date().toISOString()}), data: h.data, error: h.error || null}}];
}

return [{json: {ok: true, domain, action, client, mode, meta: Object.assign({}, meta, {execution_id: $execution.id, timestamp: new Date().toISOString()}), data: h, error: null}}];

// Format Passthrough Response v3 — with proper error classification
const h = $input.first().json;
const b = $('Build Dynamic Request').first().json;
const {domain, action, client, mode, meta} = b;

const metaOut = Object.assign({}, meta, {execution_id: $execution.id, timestamp: new Date().toISOString()});

// Detect status code from various response shapes
const sc = h.statusCode || h.status || (h.error && h.error.status) || 200;
const isErr = sc >= 400 || (h.error && !h.statusCode);

if (isErr) {
  const errBody = h.body || h.data || (h.error && h.error.message) || h;

  // Classify error type
  let errorType = 'api_error';
  if (sc === 401 || sc === 403) errorType = 'auth_error';
  else if (sc === 400) errorType = 'schema_error';
  else if (sc === 404 || sc === 422) errorType = 'logic_error';
  else if (sc >= 500) errorType = 'system_error';

  // Extract human-readable message
  let msg = domain + ' API returned ' + sc;
  if (typeof errBody === 'object' && errBody !== null) {
    msg = errBody.error?.message || errBody.message || errBody.error_description || msg;
  } else if (typeof errBody === 'string') {
    msg = errBody.slice(0, 300);
  }

  return [{json: {
    ok: false, domain, action, client, mode, meta: metaOut, data: null,
    error: {
      type: errorType, message: msg, status: sc,
      details: typeof errBody === 'string' ? errBody.slice(0, 500) : JSON.stringify(errBody).slice(0, 500)
    }
  }}];
}

const rb = h.body || h.data || h;
return [{json: {ok: true, domain, action, client, mode, meta: metaOut, data: rb, error: null}}];

// Prepare Handler Input — merges registry + tenant metadata into params for handler workflows
// Principle 2: Multi-tenant — tenant_metadata[domain] auto-injected
// Principle 3: Config-driven — zero hardcoded domain names
const v2 = $input.first().json;
const registryMeta = v2.config?.metadata || {};
const enrichedParams = Object.assign({}, v2.params, registryMeta);

// === TENANT METADATA AUTO-INJECTION (same pattern as Build Dynamic Request) ===
// tenant_metadata is domain-keyed: {"google_tag_manager": {"account_id": "123", ...}}
// Convention for handler path:
//   _base_url     → stored but not applied here (handler manages its own URLs)
//   _header_*     → stored but not applied here (handler manages its own headers)
//   anything else → injected as param default (only if not already set by caller)
if (v2.config?.tenant_metadata && v2.config.tenant_metadata[v2.domain]) {
  const domainMeta = v2.config.tenant_metadata[v2.domain];
  for (const [key, value] of Object.entries(domainMeta)) {
    if (key === '_base_url' || key.startsWith('_header_')) {
      // Skip URL/header overrides — handler workflows manage their own HTTP layer
      continue;
    }
    if (!enrichedParams[key]) {
      enrichedParams[key] = value;
    }
  }
}

// Strip domain prefix from action: "hubspot.get" → "get"
const actionShort = v2.action.startsWith(v2.domain + '.') ? v2.action.slice(v2.domain.length + 1) : v2.action;
return [{json: {api: v2.domain, action: actionShort, client: v2.client, params: enrichedParams, domain: v2.domain, mode: v2.mode, meta: v2.meta, config: v2.config, actionConfig: v2.actionConfig, _v2: v2}}];

// API Request (Code) v3 — with proper error preservation
// Bypasses HTTP Request node jsonBody expression bug (n8n #15996, #18181)
const input = $input.first().json;
const {
  requestUrl, requestMethod, requestHeaders, requestBody,
  domain, action, client, mode, meta, config
} = input;

const options = {
  method: requestMethod || 'POST',
  url: requestUrl,
  headers: Object.assign({}, requestHeaders || {}),
  returnFullResponse: true,
  ignoreHttpStatusErrors: true,
  timeout: 120000,
};

if (requestMethod !== 'GET' && requestBody !== null && requestBody !== undefined) {
  options.body = requestBody;
  options.json = true;
}

try {
  const response = await this.helpers.httpRequest(options);

  // With returnFullResponse + ignoreHttpStatusErrors, response = { body, headers, statusCode }
  if (response && typeof response === 'object' && 'statusCode' in response) {
    return [{ json: response }];
  }

  // Fallback: if returnFullResponse didn't work, response is just the body
  return [{ json: response }];
} catch (error) {
  // Extract real status code from error
  let status = 500;
  let errDetail = error.message || 'Unknown error';
  let rawBody = null;

  // Try to extract actual HTTP status from error
  if (error.httpCode) status = error.httpCode;
  else if (error.statusCode) status = error.statusCode;
  else if (error.cause?.response?.statusCode) status = error.cause.response.statusCode;
  else {
    // Parse from error message: "Request failed with status code NNN"
    const match = errDetail.match(/status code (\d+)/);
    if (match) status = parseInt(match[1]);
  }

  // Try to extract response body
  try {
    if (error.cause?.response?.body) rawBody = error.cause.response.body;
    else if (error.response?.data) rawBody = error.response.data;
    else if (error.response?.body) rawBody = error.response.body;
  } catch(e) {}

  return [{ json: {
    statusCode: status,
    body: rawBody,
    error: {
      message: errDetail,
      code: error.code || 'ERR_REQUEST',
      status: status,
      raw_body: rawBody ? JSON.stringify(rawBody).slice(0, 500) : null
    }
  }}];
}

// Prepare Infra URLs — resolves $vars once, passes as data
// Centralizes all infrastructure URLs so HTTP Request nodes have zero hardcoded values
