  }
}}];

// Rate Limit Check v5 — Self-Healing + Paginated read + append-only counters + AI budget
const input = $input.first().json;
const body = input.body || {};
const domain = body.domain || 'unknown';
const client = body.client || 'unknown';
const keyScope = input.keyScope || 'standard';
const keyName = input.keyName || 'unknown';

const AI_DOMAINS = new Set(['anthropic','openai','gemini','deepseek','groq','openrouter','perplexity','bedrock']);
const isAI = AI_DOMAINS.has(domain);

const HOURLY_LIMITS = {
  anthropic:  { standard: 20,  internal: 50,  master: 100 },
  openai:     { standard: 20,  internal: 50,  master: 100 },
  gemini:     { standard: 30,  internal: 60,  master: 120 },
  deepseek:   { standard: 30,  internal: 60,  master: 120 },
  groq:       { standard: 50,  internal: 100, master: 200 },
  openrouter: { standard: 20,  internal: 50,  master: 100 },
  perplexity: { standard: 20,  internal: 50,  master: 100 },
  bedrock:    { standard: 20,  internal: 50,  master: 100 },
  hubspot:    { standard: 200, internal: 500, master: 1000 },
  salesforce: { standard: 100, internal: 250, master: 500 },
  google_ads: { standard: 100, internal: 200, master: 500 },
  ga4:        { standard: 100, internal: 200, master: 500 },
  gmail:      { standard: 200, internal: 500, master: 1000 },
  drive:      { standard: 200, internal: 500, master: 1000 },
  sheets:     { standard: 200, internal: 500, master: 1000 },
  slack:      { standard: 200, internal: 500, master: 1000 },
  notion:     { standard: 200, internal: 500, master: 1000 },
  wordpress:  { standard: 100, internal: 250, master: 500 },
  semrush:    { standard: 50,  internal: 100, master: 200 },
  _default:   { standard: 100, internal: 250, master: 500 }
};

const AI_BUDGET = { standard: 10.00, internal: 25.00, master: 50.00 };

const host = $vars.N8N_HOST;
const apiKey = $vars.N8N_INTERNAL_API_KEY;
let rlTableId = $vars.RATE_LIMIT_TABLE_ID;
const costTableId = $vars.AI_COST_TRACKER_TABLE_ID;
const now = new Date();
const hourBucket = now.toISOString().slice(0, 13);

// ─── SELF-HEALING: Rate Limit Table Cleanup (once per hour) ───
const CLEANUP_INTERVAL_MS = 60 * 60 * 1000; // 1 hour
const CLEANUP_THRESHOLD = 500;
const lastCleanup = $vars.RATE_LIMIT_LAST_CLEANUP;
const cleanupDue = !lastCleanup || (Date.now() - new Date(lastCleanup).getTime()) > CLEANUP_INTERVAL_MS;

if (cleanupDue && rlTableId && host && apiKey) {
  try {
    // Count rows (up to 3 pages = 750 max scan)
    let totalRows = 0;
    let cursor = null;
    for (let page = 0; page < 3; page++) {
      const url = host + '/api/v1/data-tables/' + rlTableId + '/rows?limit=250' + (cursor ? '&cursor=' + cursor : '');
      const resp = await this.helpers.httpRequest({ method: 'GET', url, headers: { 'X-N8N-API-KEY': apiKey }, json: true, timeout: 5000 });
      totalRows += (resp.data || []).length;
      cursor = resp.nextCursor || null;
      if (!cursor || totalRows > CLEANUP_THRESHOLD) break;
    }

    if (totalRows > CLEANUP_THRESHOLD) {
      // DELETE bloated table
      await this.helpers.httpRequest({
        method: 'DELETE', url: host + '/api/v1/data-tables/' + rlTableId,
        headers: { 'X-N8N-API-KEY': apiKey }, timeout: 10000
      });

      // CREATE fresh table
      const createResp = await this.helpers.httpRequest({
        method: 'POST', url: host + '/api/v1/data-tables',
        headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: 'rate_limit_counters',
          columns: [
            { name: 'client', type: 'string' },
            { name: 'domain', type: 'string' },
            { name: 'hour', type: 'string' },
            { name: 'ts', type: 'string' }
          ]
        }),
        json: true, timeout: 10000
      });
      const newTableId = createResp.id;

      // UPDATE variables (lookup by key, no hardcoded IDs)
      const varsResp = await this.helpers.httpRequest({
        method: 'GET', url: host + '/api/v1/variables',
        headers: { 'X-N8N-API-KEY': apiKey }, json: true, timeout: 5000
      });
      for (const v of (varsResp.data || [])) {
        if (v.key === 'RATE_LIMIT_TABLE_ID') {
          await this.helpers.httpRequest({
            method: 'PUT', url: host + '/api/v1/variables/' + v.id,
            headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
            body: JSON.stringify({ key: 'RATE_LIMIT_TABLE_ID', value: newTableId }),
            timeout: 5000
          });
        }
        if (v.key === 'RATE_LIMIT_LAST_CLEANUP') {
          await this.helpers.httpRequest({
            method: 'PUT', url: host + '/api/v1/variables/' + v.id,
            headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
            body: JSON.stringify({ key: 'RATE_LIMIT_LAST_CLEANUP', value: now.toISOString() }),
            timeout: 5000
          });
        }
      }
      // Use new table for the rest of this request
      rlTableId = newTableId;
    } else {
      // Under threshold — just update last-check timestamp
      const varsResp = await this.helpers.httpRequest({
        method: 'GET', url: host + '/api/v1/variables',
        headers: { 'X-N8N-API-KEY': apiKey }, json: true, timeout: 5000
      });
      for (const v of (varsResp.data || [])) {
        if (v.key === 'RATE_LIMIT_LAST_CLEANUP') {
          await this.helpers.httpRequest({
            method: 'PUT', url: host + '/api/v1/variables/' + v.id,
            headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
            body: JSON.stringify({ key: 'RATE_LIMIT_LAST_CLEANUP', value: now.toISOString() }),
            timeout: 5000
          });
          break;
        }
      }
    }
  } catch (e) {
    // Fail open — cleanup failure must never block gateway requests
  }
}
// ─── END SELF-HEALING ───

try {
  // ── CHECK 1: Per-client hourly rate limit (paginated read) ──
  let hourlyCount = 0;
  const domainLimits = HOURLY_LIMITS[domain] || HOURLY_LIMITS._default;
  const hourlyLimit = domainLimits[keyScope] || domainLimits.standard;

  if (rlTableId) {
    let cursor = null;
    do {
      const url = host + '/api/v1/data-tables/' + rlTableId + '/rows?limit=250' + (cursor ? '&cursor=' + cursor : '');
      const resp = await this.helpers.httpRequest({
        method: 'GET', url, headers: { 'X-N8N-API-KEY': apiKey }, json: true, timeout: 5000
      });
      for (const row of (resp.data || [])) {
        if (row.client === client && row.domain === domain && row.hour === hourBucket) {
          hourlyCount++;
        }
      }
      cursor = resp.nextCursor || null;
      // Early exit if already over limit
      if (hourlyCount >= hourlyLimit) break;
    } while (cursor);

    if (hourlyCount >= hourlyLimit) {
      return [{json: {
        ...input, rate_limited: true,
        error: {
          type: 'rate_limit_exceeded',
          message: 'Hourly limit exceeded for ' + domain + ': ' + hourlyCount + '/' + hourlyLimit,
          details: { domain, client, key: keyName, scope: keyScope,
                     hourly_count: hourlyCount, hourly_limit: hourlyLimit,
                     hour_bucket: hourBucket,
                     retry_after_minutes: 60 - now.getMinutes() }
        }
      }}];
    }
  }

  // ── CHECK 2: AI daily budget ──
  let todaySpend = 0;
  let budget = 0;
  if (isAI && costTableId) {
    const today = now.toISOString().split('T')[0];
    budget = AI_BUDGET[keyScope] || AI_BUDGET.standard;
    const costResp = await this.helpers.httpRequest({
      method: 'GET',
      url: host + '/api/v1/data-tables/' + costTableId + '/rows?limit=250',
      headers: { 'X-N8N-API-KEY': apiKey }, json: true, timeout: 5000
    });
    for (const row of (costResp.data || [])) {
      if (row.date === today) todaySpend += parseFloat(row.est_cost_usd || 0);
    }
    if (todaySpend >= budget) {
      return [{json: {
        ...input, rate_limited: true,
        error: {
          type: 'budget_exceeded',
          message: 'Daily AI budget exceeded: $' + todaySpend.toFixed(4) + ' / $' + budget.toFixed(2),
          details: { today_spend: todaySpend, budget, domain, key: keyName, scope: keyScope }
        }
      }}];
    }
  }

  // ── PASSED: Log counter row (non-blocking) ──
  if (rlTableId) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: host + '/api/v1/data-tables/' + rlTableId + '/rows',
        headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
        body: JSON.stringify({ data: [{ client, domain, hour: hourBucket, ts: now.toISOString() }] }),
        timeout: 3000
      });
    } catch (e) { /* Non-blocking */ }
  }

  return [{json: {
    ...input, rate_limited: false,
    _rate_info: {
      hourly_count: hourlyCount + 1, hourly_limit: hourlyLimit,
      ...(isAI ? { ai_today_spend: todaySpend, ai_budget: budget } : {})
    }
  }}];

} catch (e) {
  return [{json: { ...input, rate_limited: false, _rate_info: { warning: 'Rate limit check failed: ' + e.message, fail_open: true } }}];
}

// Schema Validator v1 — validates params against MCP schema table
// Placed between Resolve Config and Resolve Gate
// Only validates passthrough actions (handlers do their own validation)
const input = $input.first().json;

// Pass through if resolution already failed
if (!input.resolved) {
  return [{json: input}];
}

const {domain, action, params, config, actionConfig} = input;

// Skip validation for handler-routed actions (handler does its own)
if (config.handler_workflow_id) {
  return [{json: input}];
}

// Skip if dry_run
if (input.meta && input.meta.dry_run) {
  return [{json: input}];
}

// Fetch schema for this domain+action
const schemaTableId = $vars.MCP_SCHEMA_TABLE_ID;
if (!schemaTableId) {
  return [{json: {...input, _schema_warn: 'no_schema_table'}}];
}

let schemaRow = null;
try {
  const host = $vars.N8N_HOST;
  const apiKey = $vars.N8N_INTERNAL_API_KEY;

  // Fetch schemas (paginated in case of overflow)
  let allSchemas = [], cursor = '', hasMore = true;
  while (hasMore) {
    const resp = await this.helpers.httpRequest({
      url: host + '/api/v1/data-tables/' + schemaTableId + '/rows?limit=250' + (cursor ? '&cursor=' + cursor : ''),
      headers: {'X-N8N-API-KEY': apiKey}, json: true, timeout: 5000
    });
    allSchemas.push(...(resp.data || []));
    cursor = resp.nextCursor || '';
    hasMore = !!resp.nextCursor && (resp.data || []).length > 0;
  }

  // Normalize action format: "anthropic.messages" → also match "messages"
  const actionShort = action.startsWith(domain + '.') ? action.slice(domain.length + 1) : action;
  schemaRow = allSchemas.find(s => s.domain === domain && (s.action === action || s.action === actionShort));
} catch(e) {
  // Fail OPEN — if schema lookup fails, allow the request through
  return [{json: {...input, _schema_warn: 'schema_fetch_failed: ' + e.message}}];
}

// No schema for this action — pass through (graceful degradation)
if (!schemaRow || !schemaRow.param_schema) {
  return [{json: {...input, _schema_warn: 'no_schema_defined'}}];
}

// Parse schema
let schema;
try {
  schema = typeof schemaRow.param_schema === 'string' 
    ? JSON.parse(schemaRow.param_schema) 
    : schemaRow.param_schema;
} catch(e) {
  return [{json: {...input, _schema_warn: 'invalid_schema_json'}}];
}

// Validate required params
const required = schema.required || {};
const missingParams = [];
const invalidParams = [];

for (const [paramName, paramSpec] of Object.entries(required)) {
  if (params[paramName] === undefined || params[paramName] === null) {
    missingParams.push({param: paramName, expected: paramSpec});
  }
}

if (missingParams.length > 0) {
  const optional = schema.optional || {};
  return [{json: {
    resolved: false,
    error: {
      type: 'schema_validation_error',
      message: 'Missing required params: ' + missingParams.map(p => p.param).join(', '),
      details: {
        missing: missingParams,
        optional_params: Object.keys(optional),
        example: schemaRow.example_request || null
      }
    },
    domain, action, client: input.client, mode: input.mode, meta: input.meta
  }}];
}

// All required params present — pass through with schema info attached
return [{json: {...input, _schema_validated: true}}];

// Track Resolve Failure (ADR-001 Phase 2)
// Fires when registry lookup fails (e.g., "No registry entry for domain X client Y")
const data = $input.first().json;
const infra = $('Prepare Infra URLs').first().json._infra || {};
const domain = data.domain || 'unknown';
const client = data.client || 'unknown';

if (infra.n8n_host && domain !== 'unknown') {
  try {
    const COUNTER_TABLE = $vars.RATE_LIMIT_TABLE_ID || 'FsTInkNFnck4KNrp';
    const now = new Date();
    const fiveMinAgo = new Date(now.getTime() - 5 * 60 * 1000).toISOString();

    await this.helpers.httpRequest({
      method: 'POST',
      url: infra.n8n_host + '/api/v1/data-tables/' + COUNTER_TABLE + '/rows',
      headers: {'X-N8N-API-KEY': infra.api_key, 'Content-Type': 'application/json'},
      body: JSON.stringify({data: [{
        domain: domain, client: client,
        error_type: (data.error && data.error.type) || 'resolve_error',
        error_message: (data.error && data.error.message) || 'unknown',
        timestamp: now.toISOString(), source: 'resolve'
      }]})
    });

    const counters = await this.helpers.httpRequest({
      method: 'GET', url: infra.n8n_host + '/api/v1/data-tables/' + COUNTER_TABLE + '/rows?limit=250',
      headers: {'X-N8N-API-KEY': infra.api_key}, json: true
    });
    const recent = (counters.data || []).filter(r => r.domain === domain && r.timestamp && r.timestamp > fiveMinAgo);
    const alertKey = 'alert_' + domain;
    const recentAlerts = (counters.data || []).filter(r => r.domain === alertKey && r.timestamp && r.timestamp > fiveMinAgo);

    if (recent.length >= 3 && recentAlerts.length === 0) {
      try {
        const slackUrl = infra.n8n_host + '/webhook/handler-google-suite';
        await this.helpers.httpRequest({
          method: 'POST', url: slackUrl,
          headers: {'x-handler-secret': infra.handler_secret, 'Content-Type': 'application/json'},
          body: JSON.stringify({
            domain: 'slack', action: 'post_message', client: 'ascend',
            params: { channel: '#n8n-alerts',
              text: ':rotating_light: *Gateway Routing Failure*\n*Domain:* ' + domain + '\n*Failures:* ' + recent.length + ' in 5 min\n*Error:* ' + ((data.error && data.error.message) || 'unknown') + '\n*Client:* ' + client
            }
          })
        });
      } catch(e) {}
      try {
        await this.helpers.httpRequest({
          method: 'POST', url: infra.n8n_host + '/api/v1/data-tables/' + COUNTER_TABLE + '/rows',
          headers: {'X-N8N-API-KEY': infra.api_key, 'Content-Type': 'application/json'},
          body: JSON.stringify({data: [{domain: alertKey, timestamp: now.toISOString(), source: 'alert_sent'}]})
        });
      } catch(e) {}
    }
  } catch(e) {}
}

return [$input.first()];
